    },
    'legend': {
        'data': xAxis_categories
    },
    'grid': {
        'left': '3%',
        'right': '4%',
        'bottom': '3%',
        'containLabel': True
    },
    'xAxis': [
        {
            'type': 'value',
            'max': 100,
            'axisLabel': {'formatter': '{value} %'}
        }
    ],
    'yAxis': [
        {
            'type': 'category',
            'data': [item['name'] for item in data]
        }
    ],
    'series': series
}

